/// Comprehensive Djot document structure with semantic preservation.
///
/// This type captures the full richness of Djot markup, including:
/// - Block-level structures (headings, lists, blockquotes, code blocks, etc.)
/// - Inline formatting (emphasis, strong, highlight, subscript, superscript, etc.)
/// - Attributes (classes, IDs, key-value pairs)
/// - Links, images, footnotes
/// - Math expressions (inline and display)
/// - Tables with full structure
///
/// Available when the `djot` feature is enabled.
class DjotContent {
  /// Plain text representation for backwards compatibility
  final String plainText;

  /// Structured block-level content
  final List<FormattedBlock> blocks;

  /// Metadata from YAML frontmatter
  final Metadata metadata;

  /// Extracted tables as structured data
  final List<Table> tables;

  /// Extracted images with metadata
  final List<DjotImage> images;

  /// Extracted links with URLs
  final List<DjotLink> links;

  /// Footnote definitions
  final List<Footnote> footnotes;

  /// Attributes mapped by element identifier (if present)
  final List<String> attributes;

  const DjotContent({
    required this.plainText,
    required this.blocks,
    required this.metadata,
    required this.tables,
    required this.images,
    required this.links,
    required this.footnotes,
    required this.attributes,
  });

  @override
  int get hashCode =>
      plainText.hashCode ^
      blocks.hashCode ^
      metadata.hashCode ^
      tables.hashCode ^
      images.hashCode ^
      links.hashCode ^
      footnotes.hashCode ^
      attributes.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is DjotContent &&
          runtimeType == other.runtimeType &&
          plainText == other.plainText &&
          blocks == other.blocks &&
          metadata == other.metadata &&
          tables == other.tables &&
          images == other.images &&
          links == other.links &&
          footnotes == other.footnotes &&
          attributes == other.attributes;
}

