  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is ModelPaths &&
          runtimeType == other.runtimeType &&
          detModel == other.detModel &&
          clsModel == other.clsModel &&
          recModel == other.recModel &&
          dictFile == other.dictFile;
}

@freezed
