      pageNumber.hashCode ^
      content.hashCode ^
      tables.hashCode ^
      imageIndices.hashCode ^
      hierarchy.hashCode ^
      isBlank.hashCode ^
      layoutRegions.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is PageContent &&
