  const TextAnnotation({
    required this.start,
    required this.end,
    required this.kind,
  });

  @override
  int get hashCode => start.hashCode ^ end.hashCode ^ kind.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is TextAnnotation &&
          runtimeType == other.runtimeType &&
          start == other.start &&
          end == other.end &&
          kind == other.kind;
}

